def _register_networktables_telemetry_backend() -> None:
    from ntcore import NetworkTableInstance

    TelemetryRegistry.register_backend(
        "",
        NetworkTablesTelemetryBackend(
            NetworkTableInstance.get_default(), "/Telemetry"
        ),
    )


def _register_networktables_tunable_backend() -> None:
    from ntcore import NetworkTableInstance

    TunableRegistry.register_backend(
        "",
        NetworkTablesTunableBackend(
            NetworkTableInstance.get_default(), "/Tunables"
        ),
    )


TelemetryRegistry.register_networktables_backend = staticmethod(
    _register_networktables_telemetry_backend
)
TunableRegistry.register_networktables_backend = staticmethod(
    _register_networktables_tunable_backend
)

